const LASTFM_API_KEY = process.env.LASTFM_API_KEY;

// ΓöÇΓöÇ Mood of the Day Configuration ΓöÇΓöÇ
const MOOD_MAP: Record<number, { mood: string; emoji: string; tag: string; gradient: string }> = {
